challenge.solution:
def check_permissions(required, granted):
    granted_set = set(granted)
    for perm in required:
        if perm in granted_set:
            continue
        print(f'missing: {perm}')
        break
    else:
        print('all permissions satisfied')

check_permissions(['read', 'write'], ['read', 'write', 'delete'])
print('---')
check_permissions(['read', 'admin'], ['read', 'write'])
